# Subtask: 实现二分查找逻辑  [✓ passed]
# ════════════════════════════════════════════════════════════
def binary_search(arr: list[int], target: int) -> int:
    """在有序列表 arr 中查找目标元素 target，若找到返回其索引，未找到返回 -1。

    Args:
        arr (list[int]): 有序整数列表。
        target (int): 要查找的目标整数。

    Returns:
        int: 目标元素的索引，如果未找到则返回 -1。
    """
    # 处理列表为空的边缘情况
    if not arr:
        return -1
    # 步骤 1: 初始化左右边界指针
    left, right = 0, len(arr) - 1
    # 步骤 2: 进入循环，条件为 left 小于等于 right
    while left <= right:
        # 步骤 3: 在循环内部，计算中间位置 mid
        mid = (left + right) // 2
        # 步骤 4: 判断中间位置的元素是否等于目标元素
        if arr[mid] == target:
            return mid
        # 步骤 5: 如果中间位置的元素大于目标元素，更新 right 为 mid - 1
        elif arr[mid] > target:
            right = mid - 1
        # 步骤 6: 如果中间位置的元素小于目标元素，更新 left 为 mid + 1
        else:
            left = mid + 1
    # 步骤 7: 若循环结束仍未找到目标元素，返回 -1
    return -1


