# Subtask: 添加错误处理  [✓ passed]
# ════════════════════════════════════════════════════════════
def binary_search(arr: list[int], target: int) -> int:
    # 步骤 1: 检查输入列表是否为空，如果为空，直接返回 -1
    if not arr:
        return -1
    # 步骤 2: 遍历列表，检查列表是否有序
    for i in range(len(arr) - 1):
        if arr[i] > arr[i + 1]:
            raise ValueError("列表必须有序")
    # 步骤 3: 若列表有序且不为空，执行原有的二分查找逻辑
    left, right = 0, len(arr) - 1
    while left <= right:
        mid = (left + right) // 2
        if arr[mid] == target:
            return mid
        elif arr[mid] < target:
            left = mid + 1
        else:
            right = mid - 1
    # 步骤 4: 如果未找到目标值，返回 -1
    return -1